## useState

### 基本用法
```jsx
const [state, setState] = useState(initialValue);
```

### 示例
```jsx
function Counter() {
  const [count, setCount] = useState(0);
  const [user, setUser] = useState({ name: '', age: 0 });

  return (
    <div>
      <p>{count}</p>
      <button onClick={() => setCount(count + 1)}>+</button>
      <button onClick={() => setCount(prev => prev + 1)}>+ (函数式)</button>
    </div>
  );
}
```

### 注意事项

**1. setState 是异步的**
```jsx
setCount(count + 1);
setCount(count + 1); // 两次都是 count+1，不是 count+2！

// 正确做法：使用函数式更新
setCount(prev => prev + 1);
setCount(prev => prev + 1); // 正确：count+2
```

**2. 对象/数组需要创建新引用**
```jsx
// ❌ 错误：直接修改（React 检测不到变化）
setUser(user => { user.name = 'Alice'; return user; });

// ✅ 正确：返回新对象
setUser(prev => ({ ...prev, name: 'Alice' }));
```

**3. 惰性初始化**
```jsx
// 如果初始值计算开销大，传入函数（只执行一次）
const [data, setData] = useState(() => expensiveCompute());
```

**4. useState 和 useReducer 的选择**
- 简单状态 → useState
- 复杂状态逻辑（多个子值、下一个状态依赖上一个）→ useReducer

## useEffect

### 基本语法
```jsx
useEffect(() => {
  // 副作用逻辑
  return () => {
    // 清理函数（可选）
  };
}, [依赖项]);
```

### 依赖项的三种情况
```jsx
// 1. 不传依赖项：每次渲染后都执行
useEffect(() => { console.log('every render'); });

// 2. 空数组：只在挂载时执行一次
useEffect(() => {
  fetch('/api/data').then(...);
}, []);

// 3. 有依赖项：依赖变化时执行
useEffect(() => {
  document.title = `Count: ${count}`;
}, [count]);
```

### 清理函数
```jsx
useEffect(() => {
  const timer = setInterval(() => setCount(c => c + 1), 1000);
  return () => clearInterval(timer); // 组件卸载或依赖变化时清理
}, []);

useEffect(() => {
  const handler = (e) => setPos({ x: e.clientX, y: e.clientY });
  window.addEventListener('mousemove', handler);
  return () => window.removeEventListener('mousemove', handler);
}, []);
```

### 常见应用
```jsx
// 数据获取（带取消）
useEffect(() => {
  const controller = new AbortController();
  fetch('/api/user', { signal: controller.signal })
    .then(res => res.json())
    .then(data => setUser(data))
    .catch(err => {
      if (err.name !== 'AbortError') setError(err);
    });
  return () => controller.abort();
}, [userId]);
```

### 注意：React 18 严格模式
开发模式下 useEffect 会执行两次（mount → unmount → mount），用于检测清理函数是否正确编写。

## useRef

### 基本用法
```jsx
const ref = useRef(initialValue);
// ref.current 访问或修改值
// 修改 ref.current 不会触发重新渲染
```

### 应用场景1：访问 DOM 元素
```jsx
function AutoFocusInput() {
  const inputRef = useRef(null);

  useEffect(() => {
    inputRef.current.focus(); // 挂载后自动聚焦
  }, []);

  return <input ref={inputRef} />;
}
```

### 应用场景2：保存可变值（不触发渲染）
```jsx
function Timer() {
  const [count, setCount] = useState(0);
  const timerRef = useRef(null);

  const start = () => {
    timerRef.current = setInterval(() => setCount(c => c + 1), 1000);
  };

  const stop = () => {
    clearInterval(timerRef.current);
  };

  return <div>...</div>;
}
```

### 应用场景3：保存上一次的值
```jsx
function usePrevious(value) {
  const ref = useRef();
  useEffect(() => {
    ref.current = value;
  });
  return ref.current; // 返回上一次渲染的值
}

function Component({ count }) {
  const prevCount = usePrevious(count);
  return <div>Now: {count}, Before: {prevCount}</div>;
}
```

### 应用场景4：保存 callback 的最新引用
```jsx
function useLatestCallback(callback) {
  const ref = useRef(callback);
  useEffect(() => { ref.current = callback; });
  return useCallback((...args) => ref.current(...args), []);
}
```

### useRef vs useState
| | useRef | useState |
|--|--------|----------|
| 触发渲染 | 否 | 是 |
| 用途 | DOM/可变值 | UI 相关状态 |

## useMemo 和 useCallback

### useMemo
缓存**计算结果**，依赖不变时跳过计算。

```jsx
const expensiveResult = useMemo(() => {
  return items.filter(item => item.active).map(item => item.value);
}, [items]);

// 只有 items 变化时才重新计算
```

### useCallback
缓存**函数引用**，依赖不变时返回同一函数。

```jsx
const handleClick = useCallback((id) => {
  dispatch({ type: 'DELETE', payload: id });
}, [dispatch]);

// handleClick 引用不变，传给子组件时不会引起不必要的重渲染
```

### 关系
```jsx
// useCallback(fn, deps) 等价于 useMemo(() => fn, deps)
const fn = useCallback(() => doSomething(a, b), [a, b]);
const fn2 = useMemo(() => () => doSomething(a, b), [a, b]);
```

### 使用时机

**使用 useMemo：**
- 计算开销大的值（复杂过滤/排序/聚合）
- 作为其他 Hook 的依赖项（保持引用稳定）

**使用 useCallback：**
- 函数作为 props 传给用 React.memo 包裹的子组件
- 函数作为 useEffect 的依赖

**不要过度使用：**
```jsx
// ❌ 没必要（简单计算）
const value = useMemo(() => a + b, [a, b]);

// ❌ 没必要（子组件没有 memo）
const handleClick = useCallback(() => setCount(c => c + 1), []);

// ✅ 有意义（开销大）
const sortedList = useMemo(() =>
  [...largeList].sort((a, b) => a.name.localeCompare(b.name)),
  [largeList]
);
```

## useContext

### 基本用法
```jsx
// 1. 创建 Context
const ThemeContext = createContext('light');

// 2. 提供 Context
function App() {
  const [theme, setTheme] = useState('light');
  return (
    <ThemeContext.Provider value={{ theme, setTheme }}>
      <Child />
    </ThemeContext.Provider>
  );
}

// 3. 消费 Context
function Button() {
  const { theme, setTheme } = useContext(ThemeContext);
  return (
    <button
      style={{ background: theme === 'dark' ? '#333' : '#fff' }}
      onClick={() => setTheme(t => t === 'light' ? 'dark' : 'light')}
    >
      Toggle Theme
    </button>
  );
}
```

### 最佳实践
```jsx
// 创建专用 Hook，避免忘记 Provider
function useTheme() {
  const context = useContext(ThemeContext);
  if (!context) {
    throw new Error('useTheme must be used within ThemeProvider');
  }
  return context;
}

// Provider 组件封装
function ThemeProvider({ children }) {
  const [theme, setTheme] = useState('light');
  return (
    <ThemeContext.Provider value={{ theme, setTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}
```

### 性能注意
Context 值变化时，所有消费该 Context 的组件都会重新渲染：
```jsx
// ❌ 问题：value 是新对象，每次渲染都变化
<Context.Provider value={{ user, setUser }}>

// ✅ 解决：useMemo 稳定引用
const value = useMemo(() => ({ user, setUser }), [user]);
<Context.Provider value={value}>

// 或者拆分 Context
const UserContext = createContext(null);
const UserDispatchContext = createContext(null);
```

## React 生命周期

### 类组件生命周期
```jsx
class MyComponent extends React.Component {
  constructor(props) {
    super(props);
    this.state = { count: 0 };
    // 初始化 state，绑定方法
  }

  static getDerivedStateFromProps(props, state) {
    // 每次渲染前调用，返回新 state 或 null
    return null;
  }

  componentDidMount() {
    // 挂载后：发起请求、订阅事件
  }

  shouldComponentUpdate(nextProps, nextState) {
    // 返回 false 可以阻止渲染（性能优化）
    return true;
  }

  getSnapshotBeforeUpdate(prevProps, prevState) {
    // DOM 更新前获取快照（如滚动位置）
    return null;
  }

  componentDidUpdate(prevProps, prevState, snapshot) {
    // 更新后：可以操作 DOM 或发起新请求
    if (prevProps.id !== this.props.id) {
      this.fetchData();
    }
  }

  componentWillUnmount() {
    // 卸载前：清理定时器、取消请求、移除监听
  }

  componentDidCatch(error, info) {
    // 错误边界
  }
}
```

### 函数组件对应关系
```jsx
useEffect(() => {
  // componentDidMount
  return () => {
    // componentWillUnmount
  };
}, []);

useEffect(() => {
  // componentDidUpdate（依赖变化时）
}, [dep]);

// shouldComponentUpdate → React.memo + 自定义比较
// getSnapshotBeforeUpdate → useLayoutEffect（近似）
```

## 受控组件 vs 非受控组件

### 受控组件
表单数据由 React 的 state 控制。

```jsx
function ControlledForm() {
  const [value, setValue] = useState('');

  return (
    <input
      value={value}  // 受 state 控制
      onChange={(e) => setValue(e.target.value)}
    />
  );
}
```

**优点：**
- 实时验证
- 根据输入动态更新其他 UI
- 可以格式化输入（如限制只能输入数字）

### 非受控组件
表单数据由 DOM 自身管理，通过 ref 获取值。

```jsx
function UncontrolledForm() {
  const inputRef = useRef(null);

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log(inputRef.current.value);
  };

  return (
    <form onSubmit={handleSubmit}>
      <input ref={inputRef} defaultValue="default" />
      <button type="submit">Submit</button>
    </form>
  );
}
```

**优点：**
- 代码简单
- 与非 React 代码集成更方便
- 文件上传必须用非受控

### 对比
| | 受控 | 非受控 |
|--|------|-------|
| 数据位置 | React state | DOM |
| 实时验证 | ✅ | 困难 |
| 提交时获取值 | 通过 state | 通过 ref |
| 文件上传 | ❌ | ✅ |

### 默认值
```jsx
// 受控：value + onChange
<input value={val} onChange={...} />

// 非受控：defaultValue（不受 React 控制，只设初始值）
<input defaultValue="initial" ref={ref} />
```

## React.memo

### 基本用法
```jsx
// 普通组件：父组件重渲染时，子组件也会重渲染
function Child({ name, onClick }) {
  console.log('Child render');
  return <button onClick={onClick}>{name}</button>;
}

// memo 包裹：props 不变时跳过渲染
const MemoChild = React.memo(function Child({ name, onClick }) {
  console.log('MemoChild render');
  return <button onClick={onClick}>{name}</button>;
});
```

### 配合 useCallback 使用
```jsx
function Parent() {
  const [count, setCount] = useState(0);
  const [name] = useState('Alice');

  // ❌ 没有 useCallback：每次渲染创建新函数，memo 失效
  const handleClick = () => console.log('clicked');

  // ✅ useCallback：函数引用稳定
  const handleClick = useCallback(() => console.log('clicked'), []);

  return (
    <div>
      <button onClick={() => setCount(c => c + 1)}>+{count}</button>
      <MemoChild name={name} onClick={handleClick} />
    </div>
  );
}
```

### 自定义比较函数
```jsx
const MemoList = React.memo(
  function List({ items }) {
    return <ul>{items.map(item => <li key={item.id}>{item.name}</li>)}</ul>;
  },
  (prevProps, nextProps) => {
    // 返回 true 表示相等（不重渲染），false 表示不等（重渲染）
    return prevProps.items.length === nextProps.items.length &&
      prevProps.items.every((item, i) => item.id === nextProps.items[i].id);
  }
);
```

### 使用时机
- 组件渲染开销大（复杂 UI 或大量计算）
- 组件频繁接收到相同的 props
- 纯展示组件（没有副作用）

### 不适合 memo 的情况
- 组件很简单，memo 的对比开销 > 重渲染开销
- props 每次都不同（如传入新对象/数组）

## JSX

### 定义
JSX 是 JavaScript 的语法扩展，允许在 JS 中写类似 HTML 的代码。它不是字符串也不是 HTML，而是语法糖。

### 编译过程
```jsx
// JSX
const element = <h1 className="title">Hello, {name}!</h1>;

// Babel 编译后（旧版 React.createElement）
const element = React.createElement(
  'h1',
  { className: 'title' },
  'Hello, ',
  name,
  '!'
);

// React 17+ 新的 JSX Transform（无需 import React）
import { jsx as _jsx } from 'react/jsx-runtime';
const element = _jsx('h1', {
  className: 'title',
  children: ['Hello, ', name, '!']
});
```

### JSX 规则
```jsx
// 1. 必须有一个根元素（或 Fragment）
return (
  <>
    <h1>Title</h1>
    <p>Content</p>
  </>
);

// 2. 标签必须关闭
<img src="..." />
<br />

// 3. className 而不是 class
<div className="container">

// 4. 驼峰命名属性
<input onChange={...} tabIndex={0} />

// 5. JavaScript 表达式用 {}
<p>{isLoggedIn ? 'Welcome' : 'Please login'}</p>

// 6. style 是对象
<div style={{ color: 'red', fontSize: 14 }}>
```

### 条件渲染
```jsx
// && 短路
{isLoading && <Spinner />}

// 三元
{error ? <Error msg={error} /> : <Content />}

// 变量
let content;
if (isLoading) content = <Spinner />;
else content = <Data />;
return <div>{content}</div>;
```

## Props

### 基本用法
```jsx
// 传递 props
<Button color="primary" size="large" onClick={handleClick} disabled />

// 接收 props
function Button({ color, size, onClick, disabled, children }) {
  return (
    <button
      className={`btn btn-${color} btn-${size}`}
      onClick={onClick}
      disabled={disabled}
    >
      {children}
    </button>
  );
}

// 默认值
function Button({ color = 'default', size = 'medium', ...props }) {}

// 也可以在外部定义
Button.defaultProps = { color: 'default', size: 'medium' };
```

### PropTypes（运行时类型检查）
```jsx
import PropTypes from 'prop-types';

function User({ name, age, email, roles }) { ... }

User.propTypes = {
  name: PropTypes.string.isRequired,
  age: PropTypes.number,
  email: PropTypes.string,
  roles: PropTypes.arrayOf(PropTypes.string),
  onClick: PropTypes.func.isRequired,
  style: PropTypes.shape({
    color: PropTypes.string,
    fontSize: PropTypes.number,
  }),
  children: PropTypes.node,
  component: PropTypes.elementType,
};
```

### 使用 TypeScript（推荐）
```tsx
interface ButtonProps {
  color: 'primary' | 'secondary' | 'danger';
  size?: 'small' | 'medium' | 'large';
  onClick: () => void;
  disabled?: boolean;
  children: React.ReactNode;
}

function Button({ color, size = 'medium', onClick, children }: ButtonProps) {
  return <button ...>...</button>;
}
```

### Props 特性
- Props 是**只读**的（不能在组件内修改）
- 函数也可以作为 Props 传递（render props 模式）
- 所有 HTML 属性（除了 class → className）都可以作为 props

## React 18 并发特性

### 并发渲染（Concurrent Rendering）
React 18 正式启用并发模式，核心是可中断的渲染。

```jsx
// React 18 启用并发特性
import { createRoot } from 'react-dom/client';
const root = createRoot(document.getElementById('root'));
root.render(<App />);
```

### useTransition
将非紧急更新标记为「过渡」，不阻塞用户输入。

```jsx
function SearchPage() {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);
  const [isPending, startTransition] = useTransition();

  const handleSearch = (e) => {
    setQuery(e.target.value); // 紧急：立即更新输入框
    startTransition(() => {
      setResults(filterData(e.target.value)); // 非紧急：可被打断
    });
  };

  return (
    <div>
      <input value={query} onChange={handleSearch} />
      {isPending ? <Spinner /> : <Results data={results} />}
    </div>
  );
}
```

### useDeferredValue
推迟非紧急的值更新，类似 useTransition 但用于接收 props。

```jsx
function SearchResults({ query }) {
  const deferredQuery = useDeferredValue(query);
  // deferredQuery 会滞后，让输入保持响应
  const results = useMemo(
    () => expensiveSearch(deferredQuery),
    [deferredQuery]
  );
  return <List data={results} />;
}
```

### 自动批处理（Automatic Batching）
```jsx
// React 17：只在事件处理中批处理
// React 18：所有地方都自动批处理
setTimeout(() => {
  setCount(c => c + 1);
  setFlag(f => !f);
  // React 18：只触发一次重渲染 ✅
  // React 17：触发两次重渲染
});

// 如果需要取消批处理
import { flushSync } from 'react-dom';
flushSync(() => setCount(c => c + 1));
flushSync(() => setFlag(f => !f));
```

### Suspense 改进
```jsx
// React 18 支持在服务端 Suspense
<Suspense fallback={<Spinner />}>
  <Comments /> // 可以流式渲染
</Suspense>
```

## useReducer

### 基本用法
```jsx
const [state, dispatch] = useReducer(reducer, initialState);
```

### 示例：购物车
```jsx
const initialState = { items: [], total: 0 };

function cartReducer(state, action) {
  switch (action.type) {
    case 'ADD_ITEM':
      return {
        items: [...state.items, action.payload],
        total: state.total + action.payload.price
      };
    case 'REMOVE_ITEM':
      const removed = state.items.find(i => i.id === action.payload);
      return {
        items: state.items.filter(i => i.id !== action.payload),
        total: state.total - (removed?.price ?? 0)
      };
    case 'CLEAR':
      return initialState;
    default:
      return state;
  }
}

function Cart() {
  const [cart, dispatch] = useReducer(cartReducer, initialState);

  return (
    <div>
      <button onClick={() => dispatch({ type: 'ADD_ITEM', payload: item })}>
        Add
      </button>
      <p>Total: {cart.total}</p>
    </div>
  );
}
```

### 与 useState 对比
| | useState | useReducer |
|--|---------|------------|
| 适用 | 简单状态 | 复杂状态逻辑 |
| 更新方式 | setter 函数 | dispatch action |
| 可测试性 | 一般 | 高（reducer 是纯函数）|
| 状态依赖 | 独立 | 多个子值相互关联 |

### 配合 Context 实现全局状态
```jsx
const StateContext = createContext();
const DispatchContext = createContext();

function AppProvider({ children }) {
  const [state, dispatch] = useReducer(reducer, initialState);
  return (
    <StateContext.Provider value={state}>
      <DispatchContext.Provider value={dispatch}>
        {children}
      </DispatchContext.Provider>
    </StateContext.Provider>
  );
}
```

## 代码分割和懒加载

### React.lazy + Suspense
```jsx
import React, { lazy, Suspense } from 'react';

// 懒加载组件
const LazyHome = lazy(() => import('./pages/Home'));
const LazyDashboard = lazy(() => import('./pages/Dashboard'));
const LazySettings = lazy(() => import('./pages/Settings'));

function App() {
  return (
    <Suspense fallback={<LoadingSpinner />}>
      <Routes>
        <Route path="/" element={<LazyHome />} />
        <Route path="/dashboard" element={<LazyDashboard />} />
        <Route path="/settings" element={<LazySettings />} />
      </Routes>
    </Suspense>
  );
}
```

### 错误边界（Error Boundary）配合
```jsx
class ErrorBoundary extends React.Component {
  state = { hasError: false };

  static getDerivedStateFromError() {
    return { hasError: true };
  }

  componentDidCatch(error, info) {
    reportError(error, info);
  }

  render() {
    if (this.state.hasError) return <ErrorFallback />;
    return this.props.children;
  }
}

<ErrorBoundary>
  <Suspense fallback={<Spinner />}>
    <LazyComponent />
  </Suspense>
</ErrorBoundary>
```

### 动态导入（非组件）
```jsx
// 按需加载工具函数或库
async function handleExport() {
  const { default: jsPDF } = await import('jspdf');
  const doc = new jsPDF();
  doc.save('file.pdf');
}

// 条件加载
const utils = await import(condition ? './moduleA' : './moduleB');
```

### 预加载（Preloading）
```jsx
// 鼠标悬浮时预加载
const loadDashboard = () => import('./Dashboard');
const LazyDashboard = lazy(loadDashboard);

<Link
  to="/dashboard"
  onMouseEnter={loadDashboard} // 预加载
>
  Dashboard
</Link>
```

## 错误边界

### 基本实现（必须是类组件）
```jsx
class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null };
  }

  // 渲染降级 UI（同步，渲染阶段）
  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }

  // 记录错误信息（副作用，提交阶段）
  componentDidCatch(error, errorInfo) {
    // errorInfo.componentStack：组件调用栈
    console.error('Error caught:', error, errorInfo);
    logErrorToService(error, errorInfo.componentStack);
  }

  render() {
    if (this.state.hasError) {
      return this.props.fallback || (
        <div>
          <h2>Something went wrong</h2>
          <button onClick={() => this.setState({ hasError: false })}>
            Try again
          </button>
        </div>
      );
    }
    return this.props.children;
  }
}

// 使用
<ErrorBoundary fallback={<ErrorPage />}>
  <MyComponent />
</ErrorBoundary>
```

### 注意：错误边界不能捕获以下错误
- 事件处理函数中的错误（需要 try/catch）
- 异步代码（setTimeout、Promise）
- 服务端渲染
- 错误边界自身抛出的错误

```jsx
// 事件处理中的错误
function Button() {
  const handleClick = () => {
    try {
      // 可能抛出的代码
    } catch (error) {
      // 手动处理
    }
  };
  return <button onClick={handleClick}>Click</button>;
}
```

### react-error-boundary 库（函数组件友好）
```jsx
import { ErrorBoundary } from 'react-error-boundary';

function ErrorFallback({ error, resetErrorBoundary }) {
  return (
    <div>
      <p>Error: {error.message}</p>
      <button onClick={resetErrorBoundary}>Retry</button>
    </div>
  );
}

<ErrorBoundary
  FallbackComponent={ErrorFallback}
  onError={(error) => logError(error)}
  onReset={() => refetch()}
>
  <Component />
</ErrorBoundary>
```

## React Portal

### 定义
Portal 允许将子组件渲染到父组件 DOM 层级之外的 DOM 节点中。

```jsx
import { createPortal } from 'react-dom';

function Modal({ isOpen, onClose, children }) {
  if (!isOpen) return null;

  return createPortal(
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content" onClick={e => e.stopPropagation()}>
        {children}
      </div>
    </div>,
    document.body // 渲染到 body 下，而不是父组件内
  );
}
```

### 使用场景

**1. 模态框（Modal）**
```jsx
// 避免父元素的 overflow:hidden、z-index 影响
function Dialog({ title, children, onClose }) {
  return createPortal(
    <div className="dialog">
      <h2>{title}</h2>
      {children}
      <button onClick={onClose}>Close</button>
    </div>,
    document.getElementById('modal-root')
  );
}
```

**2. Tooltip / Dropdown**
```jsx
// 弹出层需要脱离父容器的滚动和裁剪
function Tooltip({ content, children }) {
  const [visible, setVisible] = useState(false);
  const [position, setPosition] = useState({ x: 0, y: 0 });

  return (
    <>
      <span
        onMouseEnter={e => {
          const rect = e.target.getBoundingClientRect();
          setPosition({ x: rect.left, y: rect.bottom });
          setVisible(true);
        }}
        onMouseLeave={() => setVisible(false)}
      >
        {children}
      </span>
      {visible && createPortal(
        <div style={{ position: 'fixed', left: position.x, top: position.y }}>
          {content}
        </div>,
        document.body
      )}
    </>
  );
}
```

### Portal 的事件冒泡
虽然 Portal 在 DOM 中渲染到了其他位置，但**事件冒泡仍然按照 React 组件树**传播：

```jsx
function Parent() {
  return (
    <div onClick={() => console.log('Parent clicked')}>
      <Modal> // Modal 内部点击也会触发 Parent 的 onClick
        <button>Click me</button>
      </Modal>
    </div>
  );
}
```

## 自定义 Hook

### 规则
- 函数名以 `use` 开头
- 只能在函数组件或其他 Hook 内调用
- 可以调用其他 Hook

### 常用自定义 Hook

**1. useFetch - 数据获取**
```jsx
function useFetch(url) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const controller = new AbortController();
    setLoading(true);

    fetch(url, { signal: controller.signal })
      .then(res => {
        if (!res.ok) throw new Error(res.statusText);
        return res.json();
      })
      .then(data => { setData(data); setLoading(false); })
      .catch(err => {
        if (err.name !== 'AbortError') {
          setError(err); setLoading(false);
        }
      });

    return () => controller.abort();
  }, [url]);

  return { data, loading, error };
}

// 使用
const { data: user, loading } = useFetch('/api/user');
```

**2. useLocalStorage - 持久化状态**
```jsx
function useLocalStorage(key, initialValue) {
  const [value, setValue] = useState(() => {
    try {
      const item = localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch {
      return initialValue;
    }
  });

  const setStoredValue = useCallback((newValue) => {
    setValue(newValue);
    localStorage.setItem(key, JSON.stringify(newValue));
  }, [key]);

  return [value, setStoredValue];
}
```

**3. useDebounce**
```jsx
function useDebounce(value, delay) {
  const [debouncedValue, setDebouncedValue] = useState(value);

  useEffect(() => {
    const timer = setTimeout(() => setDebouncedValue(value), delay);
    return () => clearTimeout(timer);
  }, [value, delay]);

  return debouncedValue;
}

const debouncedSearch = useDebounce(searchTerm, 300);
```

**4. useWindowSize**
```jsx
function useWindowSize() {
  const [size, setSize] = useState({
    width: window.innerWidth,
    height: window.innerHeight
  });

  useEffect(() => {
    const handler = () => setSize({
      width: window.innerWidth,
      height: window.innerHeight
    });
    window.addEventListener('resize', handler);
    return () => window.removeEventListener('resize', handler);
  }, []);

  return size;
}
```

## Context vs Redux

### Context API
**适合：**
- 主题、语言、用户认证等低频更新的全局数据
- 中小型应用
- 避免引入外部依赖

```jsx
// 简单场景：主题
const ThemeContext = createContext('light');
function useTheme() { return useContext(ThemeContext); }
```

**不适合：**
- 频繁更新的状态（每次更新导致所有消费者重渲染）
- 复杂的状态逻辑
- 需要时间旅行调试

### Redux
**适合：**
- 大型应用，复杂状态逻辑
- 多个组件需要访问和修改同一状态
- 需要中间件（日志、异步、持久化）
- 需要 DevTools 调试

```jsx
// Redux Toolkit（现代 Redux）
const counterSlice = createSlice({
  name: 'counter',
  initialState: { value: 0 },
  reducers: {
    increment: state => { state.value += 1; }, // 使用 Immer
    decrement: state => { state.value -= 1; },
  },
});

const { value } = useSelector(state => state.counter);
const dispatch = useDispatch();
dispatch(counterSlice.actions.increment());
```

### Zustand（轻量级替代）
```jsx
const useStore = create(set => ({
  count: 0,
  increment: () => set(state => ({ count: state.count + 1 })),
  fetchUser: async (id) => {
    const user = await getUser(id);
    set({ user });
  },
}));

// 组件中
const { count, increment } = useStore();
```

### 对比
| | Context | Redux | Zustand |
|--|---------|-------|--------|
| 学习成本 | 低 | 高 | 低 |
| 性能优化 | 手动 | 自动(selector) | 自动 |
| 调试工具 | 无 | DevTools | 有 |
| 适合场景 | 简单 | 复杂 | 中等 |

## React 性能优化策略

### 1. 避免不必要的重渲染
```jsx
// React.memo：props 相同时跳过渲染
const ExpensiveChild = React.memo(({ data }) => {
  return <HeavyComponent data={data} />;
});

// useMemo：缓存计算结果
const sortedList = useMemo(() =>
  [...list].sort((a, b) => a.name.localeCompare(b.name)),
  [list]
);

// useCallback：稳定函数引用
const handleDelete = useCallback(id => {
  setItems(items => items.filter(i => i.id !== id));
}, []);
```

### 2. 代码分割
```jsx
const HeavyChart = lazy(() => import('./HeavyChart'));

<Suspense fallback={<ChartSkeleton />}>
  <HeavyChart data={data} />
</Suspense>
```

### 3. 虚拟化长列表
```jsx
import { FixedSizeList } from 'react-window';

<FixedSizeList
  height={400}
  width={600}
  itemCount={10000}
  itemSize={35}
>
  {({ index, style }) => (
    <div style={style}>Row {index}</div>
  )}
</FixedSizeList>
```

### 4. 状态结构优化
```jsx
// ❌ 把不相关的状态放一起，任一变化导致整体重渲染
const [state, setState] = useState({ user, theme, loading });

// ✅ 拆分独立状态
const [user, setUser] = useState(null);
const [theme, setTheme] = useState('light');
const [loading, setLoading] = useState(false);
```

### 5. useTransition 推迟非紧急更新
```jsx
const [isPending, startTransition] = useTransition();
startTransition(() => setSearchResults(filter(query)));
```

### 6. 图片优化
```jsx
// 懒加载图片
<img loading="lazy" src={src} alt={alt} />
```

### 7. 避免在渲染中创建新对象/数组
```jsx
// ❌ 每次渲染都是新引用
<Child style={{ color: 'red' }} options={['a', 'b']} />

// ✅
const style = useMemo(() => ({ color: 'red' }), []);
const options = useMemo(() => ['a', 'b'], []);
<Child style={style} options={options} />
```

## Render Props 模式

### 定义
通过 props 传递函数来实现组件间逻辑共享，函数返回 React 元素。

```jsx
function MouseTracker({ render }) {
  const [position, setPosition] = useState({ x: 0, y: 0 });

  return (
    <div
      style={{ height: '100vh' }}
      onMouseMove={e => setPosition({ x: e.clientX, y: e.clientY })}
    >
      {render(position)}
    </div>
  );
}

// 使用
<MouseTracker
  render={({ x, y }) => <p>Mouse: {x}, {y}</p>}
/>
```

### children as function（更常见）
```jsx
function Toggle({ children }) {
  const [on, setOn] = useState(false);
  return children({ on, toggle: () => setOn(v => !v) });
}

<Toggle>
  {({ on, toggle }) => (
    <>
      <button onClick={toggle}>{on ? 'ON' : 'OFF'}</button>
      {on && <Modal />}
    </>
  )}
</Toggle>
```

### 数据获取 Render Props
```jsx
function Fetch({ url, children }) {
  const { data, loading, error } = useFetch(url);
  return children({ data, loading, error });
}

<Fetch url="/api/user">
  {({ data, loading, error }) => {
    if (loading) return <Spinner />;
    if (error) return <Error />;
    return <Profile user={data} />;
  }}
</Fetch>
```

### Render Props vs Hooks
现代 React 中，自定义 Hooks 通常比 Render Props 更简洁：

```jsx
// Render Props 方式
<MouseTracker render={pos => <Component {...pos} />} />

// Hooks 方式（更简洁）
function useMouse() { /* ... */ return position; }
function Component() {
  const position = useMouse();
  return <div>...</div>;
}
```

## 高阶组件（HOC）

### 定义
高阶组件是接收一个组件，返回一个新组件的函数。

```jsx
function withLoading(WrappedComponent) {
  return function WithLoadingComponent({ isLoading, ...props }) {
    if (isLoading) return <Spinner />;
    return <WrappedComponent {...props} />;
  };
}

const UserListWithLoading = withLoading(UserList);

// 使用
<UserListWithLoading isLoading={loading} users={users} />
```

### 常见 HOC 模式

**权限控制**
```jsx
function withAuth(Component) {
  return function AuthenticatedComponent(props) {
    const { isAuthenticated, isLoading } = useAuth();
    if (isLoading) return <Spinner />;
    if (!isAuthenticated) return <Redirect to="/login" />;
    return <Component {...props} />;
  };
}

const PrivateDashboard = withAuth(Dashboard);
```

**日志记录**
```jsx
function withLogger(Component, name) {
  return function LoggedComponent(props) {
    useEffect(() => {
      console.log(`[${name}] mounted`);
      return () => console.log(`[${name}] unmounted`);
    }, []);
    return <Component {...props} />;
  };
}
```

### HOC 注意事项
```jsx
// 1. 转发 ref
function withFeature(Component) {
  const Enhanced = React.forwardRef((props, ref) => (
    <Component ref={ref} {...props} />
  ));
  Enhanced.displayName = `withFeature(${Component.displayName || Component.name})`;
  return Enhanced;
}

// 2. 复制静态方法
import hoistNonReactStatics from 'hoist-non-react-statics';
hoistNonReactStatics(Enhanced, WrappedComponent);

// 3. 不要在 render 中调用 HOC
// ❌ 每次渲染都创建新组件
render() { const Enhanced = withFeature(Component); return <Enhanced />; }
// ✅ 在组件外定义
const Enhanced = withFeature(Component);
```

### HOC vs Hooks
现代 React 优先使用 Hooks，HOC 主要用于：
- 需要劫持渲染（条件渲染、重定向）
- 与旧代码兼容

## useLayoutEffect vs useEffect

### 执行时机差异
```
渲染流程：
1. 组件渲染（生成虚拟 DOM）
2. React 更新真实 DOM
3. useLayoutEffect 同步执行 ← 阻塞浏览器绘制
4. 浏览器绘制（用户看到更新）
5. useEffect 异步执行
```

### 代码对比
```jsx
function Component() {
  const [size, setSize] = useState(0);
  const ref = useRef(null);

  // useEffect：DOM 更新后异步执行，可能闪烁
  useEffect(() => {
    const rect = ref.current.getBoundingClientRect();
    setSize(rect.width); // 可能导致第二次渲染后才看到正确布局
  }, []);

  // useLayoutEffect：DOM 更新后同步执行，在浏览器绘制前
  useLayoutEffect(() => {
    const rect = ref.current.getBoundingClientRect();
    setSize(rect.width); // 在绘制前完成，不会闪烁
  }, []);

  return <div ref={ref} style={{ width: size }}>{size}px</div>;
}
```

### 使用场景

**useLayoutEffect 适用：**
- 需要同步读取/修改 DOM（防止视觉闪烁）
- Tooltip 定位
- 动画的初始状态设置
- 需要在用户看到前完成的 DOM 操作

**useEffect 适用（大多数情况）：**
- 数据获取
- 事件订阅
- 定时器
- 不需要同步的副作用

### 服务端渲染注意
`useLayoutEffect` 在 SSR 中会产生警告（服务端没有 DOM），需要用 `useEffect` 或条件执行：
```jsx
const useIsomorphicLayoutEffect =
  typeof window !== 'undefined' ? useLayoutEffect : useEffect;
```

## forwardRef

### 为什么需要 forwardRef？
ref 默认不作为 props 传递，如果想让父组件通过 ref 访问子组件的 DOM，需要 `React.forwardRef`。

### 基本用法
```jsx
// 不使用 forwardRef：父组件无法获取 Input 的 DOM
function Input({ label, ...props }) {
  return <input {...props} />;
}

// 使用 forwardRef
const Input = React.forwardRef(function Input({ label, ...props }, ref) {
  return (
    <div>
      <label>{label}</label>
      <input ref={ref} {...props} />
    </div>
  );
});
Input.displayName = 'Input'; // 调试时显示名称

// 父组件使用
function Form() {
  const inputRef = useRef(null);

  return (
    <div>
      <Input label="Name" ref={inputRef} />
      <button onClick={() => inputRef.current.focus()}>Focus</button>
    </div>
  );
}
```

### 配合 useImperativeHandle
限制父组件能访问的 API（封装内部实现）：

```jsx
const FancyInput = React.forwardRef((props, ref) => {
  const inputRef = useRef();

  // 只暴露特定的方法
  useImperativeHandle(ref, () => ({
    focus() { inputRef.current.focus(); },
    clear() { inputRef.current.value = ''; },
    getValue() { return inputRef.current.value; }
    // 不暴露完整的 DOM 节点
  }), []);

  return <input ref={inputRef} {...props} />;
});

// 父组件
const ref = useRef();
ref.current.focus();     // ✅
ref.current.getValue();  // ✅
ref.current.innerHTML;   // undefined（未暴露）
```

### TypeScript 中的类型
```tsx
const Input = React.forwardRef<HTMLInputElement, InputProps>(
  ({ label, ...props }, ref) => (
    <input ref={ref} {...props} />
  )
);
```

## Suspense

### 基本概念
Suspense 允许组件在渲染时「等待」某些内容，同时显示 fallback。

### 代码分割（最常用）
```jsx
const LazyComponent = lazy(() => import('./HeavyComponent'));

<Suspense fallback={<Skeleton />}>
  <LazyComponent />
</Suspense>
```

### 数据获取（React 18 + 支持的数据库）
```jsx
// React Query 配合 Suspense
function UserProfile({ userId }) {
  // 如果数据未就绪，抛出 Promise，Suspense 捕获
  const { data: user } = useQuery({
    queryKey: ['user', userId],
    queryFn: () => getUser(userId),
    suspense: true, // 启用 Suspense 模式
  });

  return <div>{user.name}</div>; // 到这里数据一定已就绪
}

<Suspense fallback={<UserSkeleton />}>
  <ErrorBoundary fallback={<ErrorMessage />}>
    <UserProfile userId={1} />
  </ErrorBoundary>
</Suspense>
```

### 嵌套 Suspense
```jsx
// 不同区域独立加载
<Layout>
  <Suspense fallback={<HeaderSkeleton />}>
    <Header />
  </Suspense>

  <Suspense fallback={<MainSkeleton />}>
    <MainContent />
    <Suspense fallback={<SidebarSkeleton />}>
      <Sidebar />
    </Suspense>
  </Suspense>
</Layout>
```

### React 18 Streaming SSR
```jsx
// 服务端流式渲染
// 不等待所有数据，先发送 HTML 框架，再流式补充内容
import { renderToPipeableStream } from 'react-dom/server';

const { pipe } = renderToPipeableStream(
  <App />,
  {
    bootstrapScripts: ['/main.js'],
    onShellReady() { pipe(res); }
  }
);
```

## React 批处理

### 什么是批处理
将多次 setState 合并为一次重渲染，提高性能。

### React 17 的批处理
```jsx
// ✅ React 事件处理中自动批处理
function handleClick() {
  setCount(c => c + 1);
  setFlag(f => !f);
  // 只触发一次重渲染
}

// ❌ setTimeout/Promise 中不批处理（React 17）
setTimeout(() => {
  setCount(c => c + 1); // 触发一次渲染
  setFlag(f => !f);     // 再触发一次渲染
}, 0);

async function fetchAndUpdate() {
  const data = await fetch('/api');
  setData(data);   // 触发一次渲染
  setLoading(false); // 再触发一次渲染
}
```

### React 18 自动批处理
```jsx
// React 18 在所有场景都自动批处理
setTimeout(() => {
  setCount(c => c + 1);
  setFlag(f => !f);
  // 只触发一次重渲染 ✅
}, 0);

async function fetchAndUpdate() {
  const data = await fetch('/api');
  setData(data);     // 合并
  setLoading(false); // 合并
  // 只触发一次重渲染 ✅
}
```

### 手动控制（flushSync）
```jsx
import { flushSync } from 'react-dom';

function handleClick() {
  // 强制同步刷新（退出批处理）
  flushSync(() => {
    setCount(c => c + 1);
    // 立即重渲染
  });
  // 此时 DOM 已更新
  flushSync(() => {
    setFlag(f => !f);
    // 再次立即重渲染
  });
}

// 使用场景：需要在 setState 后立即读取 DOM
flushSync(() => setItems([...items, newItem]));
listRef.current.scrollToEnd(); // DOM 已更新
```

## SSR vs CSR

### CSR（客户端渲染）
```
1. 浏览器下载 HTML（空壳）
2. 下载 JS Bundle
3. 执行 JS，React 渲染组件
4. 发起数据请求
5. 渲染内容
```

**优点：** 交互流畅、服务器压力小
**缺点：** 首屏慢、SEO 差

### SSR（服务端渲染）
```
1. 服务器获取数据
2. 服务器渲染 HTML
3. 浏览器下载并显示 HTML（立即可见）
4. 下载 JS Bundle
5. Hydration（水合）：React 接管事件处理
```

**优点：** 首屏快、SEO 友好
**缺点：** 服务器压力大、TTFB（首字节时间）依赖服务器

### Next.js 中的渲染策略
```jsx
// 1. SSR（每次请求都重新渲染）
export async function getServerSideProps(context) {
  const user = await fetchUser(context.params.id);
  return { props: { user } };
}

// 2. SSG（构建时生成静态 HTML）
export async function getStaticProps() {
  const posts = await fetchPosts();
  return { props: { posts }, revalidate: 60 }; // ISR: 60秒后重新生成
}

// 3. App Router（React Server Components）
async function Page({ params }) {
  const data = await fetch(`/api/${params.id}`);
  // 服务端组件，直接 async/await
  return <div>{data.name}</div>;
}
```

### Hydration（水合）
```
SSR 输出的是静态 HTML，客户端 React 需要「水合」：
1. React 读取 SSR HTML
2. 重建虚拟 DOM 树
3. 将事件处理函数绑定到 DOM

注意：水合失败（Mismatch）会导致整个组件重新渲染
```

## useEffect 陷阱和最佳实践

### 陷阱1：无限循环
```jsx
// ❌ 依赖项是每次渲染都变化的对象/数组
useEffect(() => {
  fetchData(options);
}, [options]); // options = { type: 'all' } 每次渲染都是新对象

// ✅ 解决方案1：使用 useMemo 稳定引用
const stableOptions = useMemo(() => ({ type: 'all' }), []);

// ✅ 解决方案2：使用基本类型作为依赖
useEffect(() => {
  fetchData({ type: optionType });
}, [optionType]);
```

### 陷阱2：过期闭包（Stale Closure）
```jsx
// ❌ 闭包捕获了旧的 count 值
const [count, setCount] = useState(0);
useEffect(() => {
  const timer = setInterval(() => {
    console.log(count); // 永远是 0！
    setCount(count + 1); // 永远设为 1！
  }, 1000);
  return () => clearInterval(timer);
}, []); // 缺少 count 依赖

// ✅ 解决方案1：添加依赖项
useEffect(() => { ... }, [count]);

// ✅ 解决方案2：使用函数式更新（更好）
setCount(prev => prev + 1); // 不需要闭包捕获 count
```

### 陷阱3：依赖函数
```jsx
// ❌ 每次渲染 fetchData 都是新函数
function Component({ userId }) {
  const fetchData = async () => { /* ... */ };
  useEffect(() => {
    fetchData();
  }, [fetchData]); // 无限循环！

  // ✅ 方案1：把函数移入 effect
  useEffect(() => {
    async function fetchData() { /* ... */ }
    fetchData();
  }, [userId]);

  // ✅ 方案2：useCallback 稳定函数引用
  const fetchData = useCallback(async () => { /* ... */ }, [userId]);
  useEffect(() => { fetchData(); }, [fetchData]);
}
```

### 最佳实践
```jsx
// 1. 每个 effect 只做一件事
// 2. 正确清理副作用
// 3. 不要忽略依赖项（eslint-plugin-react-hooks 帮助检查）
// 4. 异步操作要处理取消和竞态
useEffect(() => {
  let cancelled = false;
  async function load() {
    const data = await fetchUser(userId);
    if (!cancelled) setUser(data);
  }
  load();
  return () => { cancelled = true; };
}, [userId]);
```

## React Server Components

### 概念
RSC 是在服务器上渲染的组件，渲染结果发送到客户端，不包含 JS。

```
传统 SSR：服务器渲染 HTML → 客户端下载所有 JS → Hydration
RSC：服务器渲染组件 → 发送序列化结果 → 客户端合并（无需 Hydration）
```

### Next.js App Router 中的使用
```jsx
// app/page.tsx - 默认是 Server Component
async function UserPage({ params }) {
  // 直接在服务端查询数据库！
  const user = await db.user.findUnique({ where: { id: params.id } });
  const posts = await db.post.findMany({ where: { userId: params.id } });

  return (
    <div>
      <UserProfile user={user} />
      <PostList posts={posts} />
      {/* 客户端组件 */}
      <LikeButton postId={posts[0].id} />
    </div>
  );
}

// LikeButton.tsx - 客户端组件（需要交互）
'use client';

function LikeButton({ postId }) {
  const [liked, setLiked] = useState(false);
  return <button onClick={() => setLiked(l => !l)}>Like</button>;
}
```

### Server Component 的限制
```jsx
// ❌ Server Component 不能用：
// - useState, useEffect 等 Hooks
// - 事件处理函数
// - 浏览器 API
// - Context（读取）

// ✅ Server Component 可以：
// - 直接访问数据库、文件系统
// - 使用 async/await
// - 访问服务器端数据（headers, cookies）
import { cookies, headers } from 'next/headers';
const token = cookies().get('token');
```

### 优势
1. **零 JS 开销**：Server Component 的代码不发送到客户端
2. **直接访问后端资源**：数据库、文件系统、内部 API
3. **自动代码分割**：只发送客户端组件的 JS
4. **安全性**：敏感逻辑留在服务器

### Server Actions
```jsx
// app/actions.ts
'use server';

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string;
  await db.post.create({ data: { title } });
  revalidatePath('/posts');
}

// 在组件中使用
<form action={createPost}>
  <input name="title" />
  <button type="submit">Create</button>
</form>
```

## React Scheduler

### 核心问题
如何在不阻塞用户交互的情况下，执行大量 JS 计算？

### 时间分片（Time Slicing）
```js
// React Scheduler 的工作方式（简化）
const frameInterval = 5; // 每帧最多工作 5ms

function performWorkUntilDeadline() {
  const deadline = Date.now() + frameInterval;

  while (hasWork()) {
    if (Date.now() >= deadline) {
      // 时间到，让出主线程
      scheduleNextWork();
      return;
    }
    doNextUnit();
  }
}

// 使用 MessageChannel 实现让步（比 setTimeout 更快）
const channel = new MessageChannel();
channel.port1.onmessage = performWorkUntilDeadline;
channel.port2.postMessage(null);
```

### 优先级队列
```js
// 5个优先级
ImmediatePriority = 1  // -1ms（已过期）
UserBlockingPriority = 2  // 250ms
NormalPriority = 3  // 5000ms
LowPriority = 4  // 10000ms
IdlePriority = 5  // 无限期

// 过期时间 = 当前时间 + 过期时间间隔
// 最小堆排序，每次取最紧急的任务
```

### Lane 模型（React 18）
```
Lanes 是位图，每种类型的更新对应一个 lane：
SyncLane            = 0b0000...00001
InputContinuousLane = 0b0000...00100
DefaultLane         = 0b0000...10000
TransitionLane1     = 0b0000100000000...

优势：可以快速用位运算判断是否有高优先级任务待处理
```

### 饥饿处理（Starvation Prevention）
```js
// 低优先级任务可能被高优先级任务一直打断（饥饿）
// React 的解决方案：
// 当低优先级任务等待时间过长（> expirationTime），
// 将其提升为同步优先级，强制执行
```

### 与 Generator 的对比
React 团队曾考虑用 Generator 实现可中断：
- 优点：天然支持暂停/恢复
- 缺点：需要调用链上所有函数都是 Generator（「染色」问题）
- 最终选择：手动管理 workInProgress 变量实现可中断

## startTransition 原理

### 基本使用
```jsx
import { startTransition, useTransition } from 'react';

// 方式1：startTransition（无 isPending）
startTransition(() => {
  setSearchResults(filter(query));
});

// 方式2：useTransition（有 isPending 状态）
const [isPending, startTransition] = useTransition();
startTransition(() => {
  setResults(expensiveFilter(query));
});
```

### 底层机制
```js
// startTransition 内部
function startTransition(scope) {
  const prevTransition = ReactCurrentBatchConfig.transition;
  // 标记当前更新为 Transition 优先级（低）
  ReactCurrentBatchConfig.transition = 1;
  try {
    scope(); // 执行状态更新
  } finally {
    ReactCurrentBatchConfig.transition = prevTransition;
  }
}
```

### 为什么不用 setTimeout 模拟？
```jsx
// setTimeout 的问题
input.onChange = (e) => {
  setQuery(e.target.value); // 立即更新（高优先级）
  setTimeout(() => {
    setResults(filter(query)); // 延迟，但会打断用户输入
  }, 0);
};

// startTransition 的优势：
// 1. 能被更高优先级任务打断（setTimeout 不会）
// 2. 有 isPending 状态标识
// 3. 如果有新的更新进来，旧的过渡被中断（不浪费时间在过时结果上）
```

### 实际表现
```jsx
function SearchPage() {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);
  const [isPending, startTransition] = useTransition();

  const onChange = (e) => {
    const value = e.target.value;
    setQuery(value); // 立即执行（同步优先级）

    startTransition(() => {
      // 如果用户继续输入，这次更新会被中断
      // 只有最新的输入才会完整计算
      setResults(expensiveSearch(value));
    });
  };

  return (
    <>
      <input value={query} onChange={onChange} />
      {isPending
        ? <div className="stale">{results}</div>
        : <div>{results}</div>
      }
    </>
  );
}
```

## 虚拟列表实现

### 原理
只渲染可见区域的元素，通过 transform 定位，总容器高度不变。

```jsx
function VirtualList({ items, itemHeight, containerHeight }) {
  const [scrollTop, setScrollTop] = useState(0);

  // 计算可见范围
  const startIndex = Math.floor(scrollTop / itemHeight);
  const visibleCount = Math.ceil(containerHeight / itemHeight);
  const endIndex = Math.min(startIndex + visibleCount + 1, items.length);

  // 加入 buffer（提前渲染几项，防止快速滚动时白屏）
  const bufferCount = 3;
  const renderStartIndex = Math.max(0, startIndex - bufferCount);
  const renderEndIndex = Math.min(items.length, endIndex + bufferCount);

  const visibleItems = items.slice(renderStartIndex, renderEndIndex);

  return (
    <div
      style={{ height: containerHeight, overflow: 'auto', position: 'relative' }}
      onScroll={(e) => setScrollTop(e.currentTarget.scrollTop)}
    >
      {/* 总高度撑开容器，使滚动条正确 */}
      <div style={{ height: items.length * itemHeight }}>
        {visibleItems.map((item, i) => (
          <div
            key={item.id}
            style={{
              position: 'absolute',
              top: (renderStartIndex + i) * itemHeight,
              height: itemHeight,
              width: '100%',
            }}
          >
            <ListItem item={item} />
          </div>
        ))}
      </div>
    </div>
  );
}
```

### 动态高度虚拟列表（更复杂）
```jsx
function DynamicVirtualList({ items }) {
  const [heights, setHeights] = useState({});
  const [scrollTop, setScrollTop] = useState(0);
  const containerRef = useRef();

  // 使用 ResizeObserver 测量每项高度
  const measureHeight = useCallback((id, el) => {
    if (!el) return;
    const observer = new ResizeObserver(entries => {
      setHeights(prev => ({
        ...prev,
        [id]: entries[0].contentRect.height
      }));
    });
    observer.observe(el);
    return () => observer.disconnect();
  }, []);

  // 计算每项的 top 位置
  const positions = useMemo(() => {
    const result = [];
    let top = 0;
    for (const item of items) {
      result.push({ id: item.id, top });
      top += heights[item.id] ?? 50; // 默认高度 50
    }
    return result;
  }, [items, heights]);

  // ... 类似上面的逻辑
}
```

### 推荐库
- `react-window`：固定高度，性能最好
- `react-virtual`（TanStack Virtual）：支持动态高度
- `react-virtuoso`：功能最全

## React 状态机

### 为什么需要状态机？
```jsx
// 普通 boolean 状态难以管理复杂流程
const [isLoading, setIsLoading] = useState(false);
const [isError, setIsError] = useState(false);
const [isSuccess, setIsSuccess] = useState(false);
// 可能出现 isLoading && isError 同时为 true 的非法状态！
```

### 用枚举状态代替多个 boolean
```jsx
const STATUS = {
  IDLE: 'idle',
  LOADING: 'loading',
  SUCCESS: 'success',
  ERROR: 'error'
};

function useFetchStatus(url) {
  const [status, setStatus] = useState(STATUS.IDLE);
  const [data, setData] = useState(null);
  const [error, setError] = useState(null);

  const fetch = useCallback(async () => {
    setStatus(STATUS.LOADING);
    try {
      const result = await fetchData(url);
      setData(result);
      setStatus(STATUS.SUCCESS);
    } catch (e) {
      setError(e);
      setStatus(STATUS.ERROR);
    }
  }, [url]);

  return { status, data, error, fetch };
}

// 使用
const { status, data, error } = useFetchStatus('/api/users');

if (status === STATUS.LOADING) return <Spinner />;
if (status === STATUS.ERROR) return <Error message={error.message} />;
if (status === STATUS.SUCCESS) return <UserList users={data} />;
return <button onClick={fetch}>Load</button>;
```

### XState（专业状态机库）
```jsx
import { useMachine } from '@xstate/react';
import { createMachine } from 'xstate';

const fetchMachine = createMachine({
  id: 'fetch',
  initial: 'idle',
  states: {
    idle: { on: { FETCH: 'loading' } },
    loading: {
      on: {
        SUCCESS: 'success',
        FAILURE: 'failure',
        CANCEL: 'idle'
      }
    },
    success: { on: { RETRY: 'loading' } },
    failure: { on: { RETRY: 'loading' } }
  }
});

function Component() {
  const [state, send] = useMachine(fetchMachine);

  return (
    <div>
      {state.matches('loading') && <Spinner />}
      {state.matches('success') && <Data />}
      <button onClick={() => send('FETCH')}>Fetch</button>
    </div>
  );
}
```

## React StrictMode

### 作用
StrictMode 是开发工具，帮助发现潜在问题。**不影响生产环境**。

```jsx
import { StrictMode } from 'react';

root.render(
  <StrictMode>
    <App />
  </StrictMode>
);
```

### 检测内容

**1. 双重调用（React 18）**
```jsx
// 开发模式下，React 会执行两次：
// - 组件函数体
// - useState/useReducer 的初始化函数
// - useEffect/useLayoutEffect（mount → unmount → mount）
// 目的：帮助发现副作用问题

function Component() {
  console.log('render'); // 开发模式打印 2 次

  useEffect(() => {
    console.log('effect'); // 开发模式执行 2 次
    return () => console.log('cleanup'); // 开发模式执行 2 次
  }, []);
}
```

**2. 过时 API 警告**
```jsx
// 使用过时生命周期方法会警告：
// UNSAFE_componentWillMount
// UNSAFE_componentWillReceiveProps
// UNSAFE_componentWillUpdate
```

**3. 检测意外的副作用**
```jsx
// 如果你的副作用无法承受被执行两次，说明缺少清理
useEffect(() => {
  const ws = new WebSocket('ws://...');
  // ❌ 没有清理：每次 mount 都创建连接，上一个连接没有关闭

  return () => ws.close(); // ✅ 正确清理
}, []);
```

**4. 检测过时 Context API**

**5. 废弃的 findDOMNode 警告**

### 最佳实践
```jsx
// 始终在开发环境使用 StrictMode
// 它帮助你养成正确编写组件的习惯
// 特别是确保 useEffect 的清理函数正确
```

## React Fragment

### 为什么需要 Fragment？
```jsx
// ❌ 问题：React 组件必须返回单个根元素
function ListItems() {
  return (
    // 需要包裹 div，但这会破坏 HTML 结构
    <div>
      <dt>Title</dt>
      <dd>Content</dd>
    </div>
  );
}
```

### Fragment 的使用
```jsx
import { Fragment } from 'react';

// 完整写法
function ListItems() {
  return (
    <Fragment>
      <dt>Title</dt>
      <dd>Content</dd>
    </Fragment>
  );
}

// 简写（最常用）
function ListItems() {
  return (
    <>
      <dt>Title</dt>
      <dd>Content</dd>
    </>
  );
}

// 在 dl 中使用
function DefinitionList() {
  const items = [{ title: 'A', content: 'a...' }];
  return (
