## React Query

### 核心概念
- **Query**：数据获取（GET），自动缓存、去重、后台刷新
- **Mutation**：数据修改（POST/PUT/DELETE）
- **QueryClient**：全局缓存管理器

### 基本使用
```jsx
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';

// 查询
function Users() {
  const { data, isLoading, error, refetch } = useQuery({
    queryKey: ['users'],          // 缓存键
    queryFn: () => fetch('/api/users').then(r => r.json()),
    staleTime: 5 * 60 * 1000,    // 5分钟内不重新获取
    gcTime: 10 * 60 * 1000,      // 10分钟后从缓存删除
    retry: 3,                     // 失败重试次数
    refetchOnWindowFocus: true,   // 窗口聚焦时重新获取
  });

  if (isLoading) return <Spinner />;
  if (error) return <Error message={error.message} />;
  return <UserList users={data} />;
}

// 变更
function CreateUser() {
  const queryClient = useQueryClient();

  const mutation = useMutation({
    mutationFn: (newUser) => fetch('/api/users', {
      method: 'POST',
      body: JSON.stringify(newUser)
    }).then(r => r.json()),
    onSuccess: () => {
      // 使 users 缓存失效，触发重新获取
      queryClient.invalidateQueries({ queryKey: ['users'] });
    },
    onError: (error) => console.error(error),
  });

  return (
    <button onClick={() => mutation.mutate({ name: 'Alice' })}>
      {mutation.isPending ? 'Creating...' : 'Create User'}
    </button>
  );
}
```

### 乐观更新
```jsx
const mutation = useMutation({
  mutationFn: updateTodo,
  onMutate: async (newTodo) => {
    await queryClient.cancelQueries({ queryKey: ['todos'] });
    const previous = queryClient.getQueryData(['todos']);
    queryClient.setQueryData(['todos'], old =>
      old.map(t => t.id === newTodo.id ? newTodo : t)
    );
    return { previous }; // 保存快照用于回滚
  },
  onError: (err, newTodo, context) => {
    queryClient.setQueryData(['todos'], context.previous); // 回滚
  },
  onSettled: () => queryClient.invalidateQueries({ queryKey: ['todos'] }),
});
```

## React 列表操作

### 不变性原则
React 状态更新必须返回新引用，不能直接修改原数组。

```jsx
const [items, setItems] = useState([
  { id: 1, name: 'Apple', done: false },
  { id: 2, name: 'Banana', done: false },
]);

// 添加
const addItem = (name) => {
  setItems(prev => [
    ...prev,
    { id: Date.now(), name, done: false }
  ]);
};

// 删除
const removeItem = (id) => {
  setItems(prev => prev.filter(item => item.id !== id));
};

// 更新（不可变方式）
const toggleItem = (id) => {
  setItems(prev => prev.map(item =>
    item.id === id ? { ...item, done: !item.done } : item
  ));
};

// 移动（交换位置）
const moveItem = (fromIndex, toIndex) => {
  setItems(prev => {
    const result = [...prev];
    const [removed] = result.splice(fromIndex, 1);
    result.splice(toIndex, 0, removed);
    return result;
  });
};
```

### 使用 Immer 简化
```jsx
import { useImmer } from 'use-immer';

const [items, updateItems] = useImmer([...]);

// 可以直接「修改」（Immer 内部创建新对象）
const toggleItem = (id) => {
  updateItems(draft => {
    const item = draft.find(i => i.id === id);
    if (item) item.done = !item.done;
  });
};
```

