### 解决的问题
在 SSR 中，服务端和客户端生成的 ID 必须一致，否则 Hydration 会失败。

```jsx
// ❌ Math.random() 或 counter 在 SSR 中不稳定
function Input({ label }) {
  const id = Math.random(); // 服务端和客户端不同！
  return (
    <>
      <label htmlFor={id}>{label}</label>
      <input id={id} />
    </>
  );
}

// ✅ useId 保证 SSR 一致性
import { useId } from 'react';

function Input({ label }) {
  const id = useId();
  return (
    <>
      <label htmlFor={id}>{label}</label>
      <input id={id} />
    </>
  );
}
```

### 一个组件多个 ID
