## React 拖拽实现

### 使用 HTML5 Drag and Drop API
```jsx
function DraggableList() {
  const [items, setItems] = useState(['Apple', 'Banana', 'Cherry']);
  const dragIndex = useRef(null);

  const handleDragStart = (e, index) => {
    dragIndex.current = index;
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e, index) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e, dropIndex) => {
    e.preventDefault();
    const from = dragIndex.current;
    if (from === dropIndex) return;

    setItems(prev => {
      const result = [...prev];
      const [removed] = result.splice(from, 1);
      result.splice(dropIndex, 0, removed);
      return result;
    });
    dragIndex.current = null;
  };

  return (
    <ul>
      {items.map((item, index) => (
        <li
          key={item}
          draggable
          onDragStart={(e) => handleDragStart(e, index)}
          onDragOver={(e) => handleDragOver(e, index)}
          onDrop={(e) => handleDrop(e, index)}
          style={{ cursor: 'grab', padding: 8 }}
        >
          {item}
        </li>
      ))}
    </ul>
  );
}
```

### 推荐库：@dnd-kit
```jsx
import {
  DndContext, closestCenter,
  KeyboardSensor, PointerSensor, useSensor, useSensors
} from '@dnd-kit/core';
import {
  arrayMove, SortableContext,
  sortableKeyboardCoordinates, verticalListSortingStrategy,
  useSortable
} from '@dnd-kit/sortable';

function SortableItem({ id }) {
  const { attributes, listeners, setNodeRef, transform, transition } = useSortable({ id });
  const style = { transform: CSS.Transform.toString(transform), transition };
  return (
    <div ref={setNodeRef} style={style} {...attributes} {...listeners}>
      {id}
    </div>
  );
}

function SortableList() {
  const [items, setItems] = useState(['1', '2', '3']);
  const sensors = useSensors(
    useSensor(PointerSensor),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
  );

  return (
    <DndContext sensors={sensors} collisionDetection={closestCenter}
      onDragEnd={({ active, over }) => {
        if (active.id !== over?.id) {
          setItems(items => arrayMove(items,
            items.indexOf(active.id), items.indexOf(over.id)
          ));
        }
      }}
    >
      <SortableContext items={items} strategy={verticalListSortingStrategy}>
        {items.map(id => <SortableItem key={id} id={id} />)}
      </SortableContext>
    </DndContext>
  );
}
```

## useSyncExternalStore（React 18）

### 解决的问题
在 React 18 并发模式下，外部 store（非 React 状态）可能出现「撕裂」（Tearing）问题——同一次渲染中读取到不同的快照。

### 基本用法
```jsx
import { useSyncExternalStore } from 'react';

// 订阅浏览器 online 状态
function useOnlineStatus() {
  return useSyncExternalStore(
    // subscribe：订阅函数，返回取消订阅函数
    (callback) => {
      window.addEventListener('online', callback);
      window.addEventListener('offline', callback);
      return () => {
        window.removeEventListener('online', callback);
        window.removeEventListener('offline', callback);
      };
    },
    // getSnapshot：返回当前快照（同步，无副作用）
    () => navigator.onLine,
    // getServerSnapshot（可选）：SSR 时的快照
    () => true
  );
}

function StatusBar() {
  const isOnline = useOnlineStatus();
  return <div>{isOnline ? '🟢 Online' : '🔴 Offline'}</div>;
}
```

### 订阅自定义 Store
```jsx
// 简单外部 store 实现
function createStore(initialState) {
  let state = initialState;
  const subscribers = new Set();

  return {
    getState: () => state,
    setState: (newState) => {
      state = { ...state, ...newState };
      subscribers.forEach(fn => fn());
    },
    subscribe: (fn) => {
      subscribers.add(fn);
      return () => subscribers.delete(fn);
    }
  };
}

const store = createStore({ count: 0 });

function Counter() {
  const count = useSyncExternalStore(
    store.subscribe,
    () => store.getState().count
  );
  return <button onClick={() => store.setState({ count: count + 1 })}>{count}</button>;
}
```

### 主要用途
- 实现自定义状态管理库
- 订阅浏览器 API（location、online、媒体查询）
- Zustand/Redux 内部使用此 Hook

## Reconciliation 详解

### 触发时机
```
state/props 变化 → render 函数 → 新虚拟 DOM → Reconciliation → 更新真实 DOM
```

### Fiber 树的协调
```js
// 每个 Fiber 节点包含
{
  type: 'div' | Function,    // 组件类型
  key: null | string,        // 列表 key
  stateNode: DOMNode | null, // 对应的 DOM 节点
  return: Fiber | null,      // 父节点
  child: Fiber | null,       // 第一个子节点
  sibling: Fiber | null,     // 下一个兄弟节点
  alternate: Fiber | null,   // 对应的旧 Fiber
  flags: number,             // 副作用标记（Placement/Update/Deletion）
  pendingProps: {},
  memoizedProps: {},
  memoizedState: {},
}
```

### beginWork 阶段（向下）
```
每个 Fiber 节点执行 beginWork：
1. 根据 type 和 props 决定如何处理
2. 函数组件：调用函数，处理 Hooks
3. 类组件：调用 render 方法
4. 对比新旧 props，决定是否跳过（bailout）
5. 生成子 Fiber（diff children）
```

### completeWork 阶段（向上）
```
bottom-up：
1. 创建 DOM 节点（如果是 HostComponent）
2. 收集副作用到 effectList
3. 向上冒泡 flags
```

### 优化：bailout
```jsx
// 满足以下条件时，跳过子树的协调
// 1. 没有待处理的 state 更新
// 2. props 没有变化（Object.is 比较）
// 3. 没有 context 变化
// 这就是 React.memo、PureComponent、shouldComponentUpdate 的底层

function Parent() {
  const [count, setCount] = useState(0);
  // Child 的 props 没变 → 如果 Child 是 memo 包裹的，会 bailout
  return <Child staticProp="value" />;
}
```

### Context 导致的低效更新
```jsx
// Context value 变化时，所有消费者都重新渲染（无法 bailout）
// 解决：拆分 Context，或使用选择器库（use-context-selector）
const { selectedItem } = useContextSelector(StoreContext, s => ({
  selectedItem: s.items[s.selectedId]
}));
```

## 原子化状态管理库对比

### Zustand（集中式）
```jsx
const useStore = create(set => ({
  count: 0,
  text: '',
  increment: () => set(s => ({ count: s.count + 1 })),
}));

// 使用选择器避免不必要的重渲染
const count = useStore(s => s.count);
```

### Jotai（原子化）
```jsx
import { atom, useAtom, useAtomValue, useSetAtom } from 'jotai';

// 原子（最小单元）
const countAtom = atom(0);
const doubleAtom = atom(get => get(countAtom) * 2); // 派生原子

function Counter() {
  const [count, setCount] = useAtom(countAtom);
  const double = useAtomValue(doubleAtom); // 只读
  return <button onClick={() => setCount(c => c + 1)}>{count} / {double}</button>;
}
```

### Recoil（Facebook 出品，已基本停止维护）
```jsx
import { atom, selector, useRecoilState } from 'recoil';

const countState = atom({ key: 'count', default: 0 });
const doubleCount = selector({
  key: 'doubleCount',
  get: ({ get }) => get(countState) * 2
});
```

### 对比
| | Zustand | Jotai | Recoil |
|--|---------|-------|-------|
| 模型 | 集中式 store | 原子化 | 原子化 |
| 包大小 | ~1KB | ~3KB | ~20KB |
| 并发模式 | 中等支持 | 完整支持 | 有问题 |
| 维护状态 | 活跃 | 活跃 | 停滞 |
| 适用场景 | 中大型应用 | 细粒度状态 | 不推荐 |

### 选择建议
- 简单应用/快速开发 → Zustand
- 需要细粒度订阅/原子化 → Jotai
- 复杂异步状态图 → Jotai（asyncAtom）
- 大型企业应用需要 DevTools → Zustand/Redux

## 竞态条件处理

### 问题场景
```jsx
// ❌ 竞态条件：快速切换 userId 时，旧请求的响应可能后于新请求
function Profile({ userId }) {
  const [user, setUser] = useState(null);

  useEffect(() => {
    fetchUser(userId).then(data => {
      setUser(data); // 如果旧请求最后返回，会覆盖新数据！
    });
  }, [userId]);
}
```

### 解决方案1：标记取消
```jsx
useEffect(() => {
  let cancelled = false;

  fetchUser(userId).then(data => {
    if (!cancelled) setUser(data); // 只有最新请求能更新状态
  });

  return () => { cancelled = true; };
}, [userId]);
```

### 解决方案2：AbortController
```jsx
useEffect(() => {
  const controller = new AbortController();

  fetch(`/api/user/${userId}`, { signal: controller.signal })
    .then(r => r.json())
    .then(data => setUser(data))
    .catch(err => {
      if (err.name !== 'AbortError') setError(err);
    });

  return () => controller.abort(); // 清理时取消旧请求
}, [userId]);
```

### 解决方案3：React Query（自动处理）
```jsx
// React Query 自动处理竞态条件
const { data: user } = useQuery({
  queryKey: ['user', userId],
  queryFn: () => fetchUser(userId)
  // 会自动忽略过时的请求结果
});
```

### 更复杂的场景：顺序依赖请求
```jsx
async function fetchSequential(ids, signal) {
  const results = [];
  for (const id of ids) {
    if (signal.aborted) throw new Error('Aborted');
    const data = await fetchItem(id);
    results.push(data);
  }
  return results;
}

useEffect(() => {
  const controller = new AbortController();
  fetchSequential(ids, controller.signal)
    .then(setResults)
    .catch(err => { if (err.message !== 'Aborted') setError(err); });
  return () => controller.abort();
}, [ids]);
```

## Dialog 可访问性

### ARIA 角色和属性
```jsx
function AccessibleDialog({ open, onClose, title, children }) {
  const dialogRef = useRef(null);

  useEffect(() => {
    if (!open) return;
    const dialog = dialogRef.current;
    const focusable = dialog.querySelectorAll(
      'a[href], button, input, select, textarea, [tabindex]:not([tabindex="-1"])'
    );
    if (focusable.length) focusable[0].focus();

    // 阻止 body 滚动
    document.body.setAttribute('aria-hidden', 'true'); // 可选
    return () => document.body.removeAttribute('aria-hidden');
  }, [open]);

  if (!open) return null;

  return createPortal(
    <div
      role="presentation"
      style={overlayStyle}
      onClick={(e) => e.target === e.currentTarget && onClose()}
    >
      <div
        ref={dialogRef}
        role="dialog"
        aria-modal="true"
        aria-labelledby="dialog-title"
        aria-describedby="dialog-desc"
        style={dialogStyle}
        onKeyDown={(e) => e.key === 'Escape' && onClose()}
      >
        <h2 id="dialog-title">{title}</h2>
        <div id="dialog-desc">{children}</div>
        <button onClick={onClose} aria-label="Close">×</button>
      </div>
    </div>,
    document.body
  );
}
```

### 可访问性检查清单
- [ ] `role="dialog"` + `aria-modal="true"`
- [ ] `aria-labelledby` 指向标题
- [ ] 打开时焦点移入对话框
- [ ] 关闭时焦点还原到触发元素
- [ ] Tab/Shift+Tab 焦点不离开对话框
- [ ] Escape 键可关闭
- [ ] 点击遮罩可关闭（非必须）

