## React 主题切换实现

### 方式1：CSS 变量 + Context
```css
/* globals.css */
:root {
  --bg: #ffffff;
  --text: #000000;
  --primary: #0070f3;
}

[data-theme='dark'] {
  --bg: #1a1a1a;
  --text: #ffffff;
  --primary: #60a5fa;
}
```

```jsx
const ThemeContext = createContext();

function ThemeProvider({ children }) {
  const [theme, setTheme] = useState(() => {
    // 读取用户偏好
    return localStorage.getItem('theme') ||
      (window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light');
  });

  const toggleTheme = useCallback(() => {
    setTheme(t => {
      const next = t === 'light' ? 'dark' : 'light';
      localStorage.setItem('theme', next);
      document.documentElement.setAttribute('data-theme', next);
      return next;
    });
  }, []);

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme);
  }, [theme]);

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}

// 组件中
function Button() {
  return (
    <button style={{
      background: 'var(--bg)',
      color: 'var(--text)',
    }}>
      Click
    </button>
  );
}
```

### 方式2：Tailwind + dark 类
```jsx
// tailwind.config.js: darkMode: 'class'

function ThemeToggle() {
  const { theme, toggleTheme } = useTheme();
  return (
    <button onClick={toggleTheme}
      className="bg-white dark:bg-gray-800 text-black dark:text-white">
      {theme === 'dark' ? '☀️' : '🌙'}
    </button>
  );
}
```

### 监听系统主题变化
```jsx
useEffect(() => {
  const media = window.matchMedia('(prefers-color-scheme: dark)');
  const handler = (e) => setTheme(e.matches ? 'dark' : 'light');
  media.addEventListener('change', handler);
  return () => media.removeEventListener('change', handler);
}, []);
```

## 单向数据流

### 概念
在 React 中，数据只能从父组件流向子组件（通过 props），子组件不能直接修改父组件的状态。

```
父组件（State）
    ↓ props
子组件（接收 props，不能反向修改）
    ↓ props
孙组件
```

### 为什么这样设计？
```jsx
// 清晰的数据流，便于调试
function Parent() {
  const [count, setCount] = useState(0);
  return (
    <div>
      <Display count={count} />
      <Counter onChange={setCount} />
    </div>
  );
}

// ❌ 不对：子组件不能直接修改 props
function Child({ count }) {
  count = count + 1; // 无效且不推荐
}

// ✅ 正确：子组件通过回调通知父组件
function Counter({ onChange }) {
  return <button onClick={() => onChange(c => c + 1)}>+</button>;
}
```

### 「状态提升」
当两个子组件需要共享状态时，将状态提升到最近的共同父组件：
```jsx
// 两个输入框实时同步
function App() {
  const [celsius, setCelsius] = useState(0);
  const fahrenheit = celsius * 9/5 + 32;

  return (
    <>
      <Input label="°C" value={celsius} onChange={setCelsius} />
      <Input label="°F" value={fahrenheit}
        onChange={f => setCelsius((f - 32) * 5/9)} />
    </>
  );
}
```

### 优点
1. 可预测：数据变化可追踪
2. 易调试：只需检查父组件的状态
3. 性能：React 知道何时需要重渲染

## useInsertionEffect（React 18）

### 执行时机
```
1. React 更新 DOM
2. useInsertionEffect 执行 ← 在 DOM 更新后、布局读取前
3. useLayoutEffect 执行
4. 浏览器绘制
5. useEffect 执行
```

### 主要用途：CSS-in-JS 库注入样式
```jsx
// 为什么需要它？
// CSS-in-JS 库需要在 DOM 更新后立即注入样式表
// 如果在 useLayoutEffect 中注入，可能错过某些布局计算

// 库内部使用示例（如 styled-components 或 Emotion）
function useCSSInjection(css) {
  useInsertionEffect(() => {
    const style = document.createElement('style');
    style.textContent = css;
    document.head.appendChild(style);
    return () => document.head.removeChild(style);
  }, [css]);
}

// styled-components v6 内部类似实现
const StyledButton = styled.button`
  background: ${props => props.primary ? 'blue' : 'white'};
`;
// 当 primary 变化时，useInsertionEffect 更新样式注入
```

### 限制
- 不能读取 `refs`（DOM 可能尚未完全准备好）
- 不能调度状态更新
- **只供 CSS-in-JS 库作者使用**，普通开发者应使用 useLayoutEffect 或 useEffect

## 通用表格组件设计

### 核心设计
```tsx
interface Column<T> {
  key: keyof T;
  title: string;
  sortable?: boolean;
  render?: (value: T[keyof T], row: T) => React.ReactNode;
  width?: number;
}

interface TableProps<T> {
  data: T[];
  columns: Column<T>[];
  pageSize?: number;
  loading?: boolean;
  rowKey: keyof T;
  onRowClick?: (row: T) => void;
}
```

### 实现
```jsx
function Table({ data, columns, pageSize = 10, loading, rowKey }) {
  const [sortConfig, setSortConfig] = useState(null); // { key, direction }
  const [currentPage, setCurrentPage] = useState(1);
  const [filters, setFilters] = useState({});

  // 筛选
  const filtered = useMemo(() => {
    return data.filter(row =>
      Object.entries(filters).every(([key, value]) =>
        !value || String(row[key]).toLowerCase().includes(value.toLowerCase())
      )
    );
  }, [data, filters]);

  // 排序
  const sorted = useMemo(() => {
    if (!sortConfig) return filtered;
    return [...filtered].sort((a, b) => {
      const aVal = a[sortConfig.key];
      const bVal = b[sortConfig.key];
      const result = aVal < bVal ? -1 : aVal > bVal ? 1 : 0;
      return sortConfig.direction === 'asc' ? result : -result;
    });
  }, [filtered, sortConfig]);

  // 分页
  const totalPages = Math.ceil(sorted.length / pageSize);
  const paged = sorted.slice((currentPage - 1) * pageSize, currentPage * pageSize);

  const handleSort = (key) => {
    setSortConfig(prev => {
      if (prev?.key === key) {
        return { key, direction: prev.direction === 'asc' ? 'desc' : 'asc' };
      }
      return { key, direction: 'asc' };
    });
  };

  if (loading) return <TableSkeleton columns={columns} rows={pageSize} />;

  return (
    <div>
      <table>
        <thead>
          <tr>
            {columns.map(col => (
              <th key={String(col.key)}
                onClick={() => col.sortable && handleSort(col.key)}
                style={{ cursor: col.sortable ? 'pointer' : 'default' }}
              >
                {col.title}
                {sortConfig?.key === col.key && (sortConfig.direction === 'asc' ? ' ↑' : ' ↓')}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {paged.map(row => (
            <tr key={String(row[rowKey])}>
              {columns.map(col => (
                <td key={String(col.key)}>
                  {col.render ? col.render(row[col.key], row) : String(row[col.key])}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
      <Pagination current={currentPage} total={totalPages} onChange={setCurrentPage} />
    </div>
  );
}
```

## Context 性能优化

### 问题
```jsx
// ❌ 任何 count/user/theme 变化，所有消费者都重渲染
const AppContext = createContext();

function Provider({ children }) {
  const [count, setCount] = useState(0);
  const [user, setUser] = useState(null);
  const [theme, setTheme] = useState('light');

  return (
    <AppContext.Provider value={{ count, setCount, user, setUser, theme, setTheme }}>
      {children}
    </AppContext.Provider>
  );
}
```

### 解决方案1：拆分 Context
```jsx
// 按更新频率拆分
const ThemeContext = createContext();
const UserContext = createContext();
const CounterContext = createContext();

// 消费者只订阅需要的 Context
function ThemeButton() {
  const { theme } = useContext(ThemeContext); // 只在 theme 变化时重渲染
}
```

### 解决方案2：分离读写 Context
```jsx
const CountContext = createContext(0);
const SetCountContext = createContext(() => {});

function Provider({ children }) {
  const [count, setCount] = useState(0);
  return (
    <SetCountContext.Provider value={setCount}> // setCount 不变
      <CountContext.Provider value={count}>
        {children}
      </CountContext.Provider>
    </SetCountContext.Provider>
  );
}

// 只需要 dispatch 的组件不会因 count 变化重渲染
function AddButton() {
  const setCount = useContext(SetCountContext);
  return <button onClick={() => setCount(c => c + 1)}>Add</button>;
}
```

### 解决方案3：use-context-selector
```jsx
import { createContext, useContextSelector } from 'use-context-selector';

const StateContext = createContext(initialState);

// 只在选择的值变化时重渲染
function Component() {
  const count = useContextSelector(StateContext, state => state.count);
  return <div>{count}</div>;
}
```

### 解决方案4：memo + useMemo
```jsx
const value = useMemo(() => ({ count, user }), [count, user]);
<Context.Provider value={value}>
```

## useOptimistic

### 概念
useOptimistic 允许在异步操作进行时，乐观地更新 UI，操作完成后同步真实结果。

### 基本用法
```jsx
import { useOptimistic } from 'react';

function MessageList({ messages, sendMessage }) {
  const [optimisticMessages, addOptimisticMessage] = useOptimistic(
    messages,
    (state, newMessage) => [
      ...state,
      { ...newMessage, sending: true } // 乐观地添加，标记为发送中
    ]
  );

  async function handleSubmit(formData) {
    const message = { text: formData.get('message'), id: Date.now() };

    // 立即乐观地更新 UI
    addOptimisticMessage(message);

    // 异步发送（此时 UI 已经更新了）
    await sendMessage(message);
    // 发送成功后，React 用真实的 messages 替换乐观状态
  }

  return (
    <div>
      {optimisticMessages.map(msg => (
        <div key={msg.id}>
          {msg.text}
          {msg.sending && <span>(Sending...)</span>}
        </div>
      ))}
      <form action={handleSubmit}>
        <input name="message" />
        <button type="submit">Send</button>
      </form>
    </div>
  );
}
```

### 点赞示例
```jsx
function LikeButton({ post }) {
  const [optimisticLikes, addOptimisticLike] = useOptimistic(
    post.likes,
    (currentLikes, delta) => currentLikes + delta
  );

  return (
    <button onClick={async () => {
      addOptimisticLike(1); // 立即 +1
      await likePost(post.id); // 实际请求
    }}>
      ❤️ {optimisticLikes}
    </button>
  );
}
```

## React 合成事件（SyntheticEvent）

### 概念
React 封装了浏览器的原生事件，创建了统一的合成事件系统。

### 事件委托
```
React 17+：事件委托到 root DOM 节点（#root）
React 16-：事件委托到 document

好处：
- 统一处理所有事件
- 减少事件监听器数量
- 统一不同浏览器的事件行为
```

### 使用方式
```jsx
function Button() {
  const handleClick = (e) => {
    // e 是 SyntheticEvent，包装了原生事件
    console.log(e.type);          // 'click'
    console.log(e.target);        // DOM 元素
    console.log(e.currentTarget); // 绑定事件的元素
    console.log(e.nativeEvent);   // 原生 Event 对象

    e.preventDefault();  // 阻止默认行为
    e.stopPropagation(); // 阻止冒泡（React 树中）

    // 异步访问事件对象
    // React 17+ 不再需要 e.persist()
    setTimeout(() => console.log(e.type), 0); // 仍然可以访问
  };

  return <button onClick={handleClick}>Click</button>;
}
```

### 事件命名
```jsx
// React 使用驼峰命名
<button onClick={fn}>       // click
<input onChange={fn}>        // change
<form onSubmit={fn}>         // submit
<div onMouseEnter={fn}>      // mouseenter
<input onKeyDown={fn}>       // keydown
<div onFocus={fn}>           // focus
<div onScroll={fn}>          // scroll（不冒泡）
```

### 与原生事件的交互
```jsx
useEffect(() => {
  // 原生事件监听
  document.addEventListener('click', nativeHandler);
  return () => document.removeEventListener('click', nativeHandler);
}, []);

// 注意：原生 stopPropagation 会阻止事件到达 React 的根节点
// 导致 React 的合成事件不会触发！
```

## Transition + Suspense 协同

### 问题场景
```jsx
// 没有 Transition：tab 切换时立即显示 Suspense fallback（loading），体验差
function App() {
  const [tab, setTab] = useState('home');
  return (
    <>
      <button onClick={() => setTab('posts')}>Posts</button>
      <Suspense fallback={<Spinner />}>
        <TabContent tab={tab} />
      </Suspense>
    </>
  );
}
```

### 配合 useTransition 保留旧 UI
```jsx
function App() {
  const [tab, setTab] = useState('home');
  const [isPending, startTransition] = useTransition();

  return (
    <>
      <button
        onClick={() => startTransition(() => setTab('posts'))}
        disabled={isPending}
      >
        {isPending ? 'Loading...' : 'Posts'}
      </button>

      {/* 切换时不立即显示 Spinner，保留旧内容直到新内容就绪 */}
      <Suspense fallback={<Spinner />}>
        <div style={{ opacity: isPending ? 0.5 : 1 }}>
          <TabContent tab={tab} />
        </div>
      </Suspense>
    </>
  );
}

// TabContent 内部触发数据加载（配合 React Query 等）
function PostsTab() {
  const { data } = useQuery({ queryKey: ['posts'], queryFn: fetchPosts, suspense: true });
  return <PostList posts={data} />;
}
```

### 工作机制
```
1. startTransition 触发 tab 更新
2. React 在后台开始渲染新 tab（可中断）
3. 新 tab 触发 Suspense（数据未就绪）
4. React 检测到是 Transition 触发的 Suspense
5. 继续显示旧内容（不显示 fallback），isPending = true
6. 数据就绪后，React 完成渲染
7. 一次性切换到新内容，isPending = false
```

## 避免不必要的重渲染

### 触发重渲染的原因
1. 组件自身的 state 变化
2. 接收到新的 props（包括引用变化的对象/数组/函数）
3. 父组件重渲染（默认行为）
4. Context 值变化

### 优化手段

**1. React.memo（记忆化组件）**
```jsx
const Child = React.memo(({ name, onDelete }) => {
  return <div onClick={() => onDelete(name)}>{name}</div>;
});
```

**2. useCallback（稳定函数引用）**
```jsx
function Parent() {
  const handleDelete = useCallback((name) => {
    setItems(items => items.filter(i => i !== name));
  }, []); // 依赖不变，引用稳定
  return <Child onDelete={handleDelete} />;
}
```

**3. useMemo（稳定对象/数组引用）**
```jsx
// ❌ 每次渲染都是新对象，memo 失效
<Child style={{ color: 'red' }} />

// ✅
const style = useMemo(() => ({ color: 'red' }), []);
<Child style={style} />
```

**4. 状态下沉（State Colocation）**
```jsx
// ❌ 父组件管理子组件状态，父更新时子也更新
function Parent() {
  const [childOpen, setChildOpen] = useState(false);
  return <>
    <HeavyComponent />
    <Child open={childOpen} setOpen={setChildOpen} />
  </>;
}

// ✅ 将状态移入子组件
function Child() {
  const [open, setOpen] = useState(false); // 状态下沉，不影响 HeavyComponent
}
```

**5. 内容提升（Children 作为 Props）**
```jsx
// ✅ 把不需要的重渲染组件通过 children 传入
function ColorBox({ children }) {
  const [color, setColor] = useState('red');
  return <div style={{ color }}>{children}</div>;
  // children 的引用由外部决定，color 变化不会导致 children 重渲染
}
<ColorBox><HeavyComponent /></ColorBox>
```

## React Hooks 实现原理

### Hooks 存储在 Fiber 节点上
```js
// 每个 Fiber 节点有 memoizedState 属性
// 存储 Hooks 链表
fiber.memoizedState = {
  memoizedState: 0,      // useState 的 state 值
  queue: { ... },        // 更新队列
  next: {                // 下一个 Hook
    memoizedState: null, // useEffect 的 effect 对象
    queue: null,
    next: null
  }
};
```

### 为什么 Hooks 不能在条件/循环中使用？
```jsx
// React 通过「调用顺序」识别 Hooks
// 第一次渲染：useState → useEffect → useState（3个Hooks，顺序固定）
// 第二次渲染必须按完全相同的顺序调用

function Component() {
  const [a] = useState(1);  // Hook #1
  const [b] = useState(2);  // Hook #2

  // ❌ 条件中的 Hook：顺序可能变化
  if (condition) {
    const [c] = useState(3); // 有时是 Hook #3，有时不存在
  }
  // React 用链表顺序访问，条件改变会错位！
}
```

### useState 简化实现
```js
let currentFiber;
let workInProgressHook;

function useState(initialState) {
  const hook = getOrCreateHook(); // 从链表获取或创建 Hook

  if (isMount) {
    // 首次渲染：初始化
    hook.memoizedState = typeof initialState === 'function'
      ? initialState()
      : initialState;
    hook.queue = { pending: null };
  }

  // 处理队列中的更新
  let state = hook.memoizedState;
  let update = hook.queue.pending;
  while (update) {
    state = typeof update.action === 'function'
      ? update.action(state)
      : update.action;
    update = update.next;
  }
  hook.queue.pending = null;
  hook.memoizedState = state;

  const setState = (action) => {
    const update = { action, next: null };
    // 将更新加入队列
    enqueueUpdate(hook.queue, update);
    // 调度重渲染
    scheduleUpdateOnFiber(currentFiber);
  };

  return [hook.memoizedState, setState];
}
```

### 闭包与 Hooks
```jsx
// Hooks 通过闭包捕获了当次渲染的状态
function Counter() {
  const [count, setCount] = useState(0);

  // 每次渲染都创建新的 handleClick
  // 闭包捕获了当次渲染的 count 值
  const handleClick = () => console.log(count);

  return <button onClick={handleClick}>{count}</button>;
}
// 这就是为什么需要 useCallback 和函数式 setState
```
